def evaluate_postfix_expression(expression):
    stack = []
    tokens = expression.split()

    operators = {
        '+': lambda a, b: a + b,
        '-': lambda a, b: a - b,
        '*': lambda a, b: a * b,
        '/': lambda a, b: a / b
    }

    for token in tokens:
        if token in operators:
            if len(stack) < 2:
                raise ValueError("Invalid postfix expression: Insufficient operands for operator " + token)
            operand2 = stack.pop()
            operand1 = stack.pop()
            result = operators[token](operand1, operand2)
            stack.append(result)
        else:
            try:
                stack.append(float(token))
            except ValueError:
                raise ValueError("Invalid token in expression: " + token)

    if len(stack) != 1:
        raise ValueError("Invalid postfix expression: Too many operands or operators")

    return stack[0]
